var seed = GetInt(parameters, "seed", context.Seed);
var time = GetFloat(parameters, "time", 0f);
var density = GetFloat(parameters, "density", 0.6f);
var speed = GetFloat(parameters, "speed", 0.8f);
var wind = GetFloat(parameters, "wind", 0f);
var length = Math.Max(2, GetInt(parameters, "length", 6));
var pixelSize = Math.Max(1, GetInt(parameters, "pixelSize", 1));

var size = context.TileSize;
var result = new PixelBuffer(size, size);

// Rain color
var cR = 150f/255f; var cG = 190f/255f; var cB = 230f/255f;

// Hash grid for raindrop distribution — grid size scales with density
var gridSize = Math.Max(6, (int)(20f * density));
var cellW = size / (float)gridSize;
var cellH = size / (float)gridSize;

// Time-driven vertical offset — wraps around seamlessly
var fallDist = time * speed * size;
var windOffset = wind * size * 0.15f;

for (var gy = 0; gy < gridSize; gy++)
{
    for (var gx = 0; gx < gridSize; gx++)
    {
        var h = HashToUnit(gx * 37 + gy * 19, seed, 111);
        if (h > density) continue;

        // X position: jitter within cell + wind shift
        var xOff = HashToUnit(gx * 7 + gy * 13, seed + 50, 222);
        var sx = (int)((gx + xOff) * cellW + windOffset) % size;
        if (sx < 0) sx += size;
        sx = (sx / pixelSize) * pixelSize;

        // Y position: base + time offset, wrapped
        var yOff = HashToUnit(gx * 11 + gy * 5, seed + 100, 333);
        var rawY = (gy * cellH + yOff * cellH + fallDist) % (size + length);
        var sy = (int)(rawY - length);

        // Wind shear: slight horizontal spread along drop length
        var windShear = wind * 0.5f;

        // Draw the raindrop as a line
        for (var l = 0; l < length; l += pixelSize)
        {
            var lx = sx + (int)(windShear * l);
            var ly = sy + l;
            // Wrap
            lx = ((lx % size) + size) % size;
            if (ly < 0 || ly >= size) continue;

            var fade = 1f - l / (float)length * 0.4f;
            result.SetPixel(lx, ly, cR * fade, cG * fade, cB * fade, Math.Clamp(fade * 0.8f, 0f, 1f));
        }
    }
}
return result;
}
